fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    let right_depth = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    (right_depth as i32) - (left_depth as i32)
}

fn compute_depth(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let n = node.borrow();
    let left_depth = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    let right_depth = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    left_depth.max(right_depth)
}

/// Rotate right around node P. Returns the new subtree root (L).
fn bostree_rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    // Update P's parent to point to L
    let p_parent_weak = p.borrow().parent_node.clone();
    if let Some(ref pw) = p_parent_weak {
        if let Some(parent) = pw.upgrade() {
            let p_is_left = {
                let par_b = parent.borrow();
                par_b.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, p))
            };
            if p_is_left {
                parent.borrow_mut().left_child_node = Some(l.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(l.clone());
            }
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    l.borrow_mut().parent_node = p_parent_weak;

    // P.left = L.right (c2)
    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    {
        let mut pb = p.borrow_mut();
        pb.left_child_node = l_right.clone();
        pb.left_child_count = l_right_count;
    }

    if let Some(ref lr) = l_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
    l.borrow_mut().right_child_node = Some(p.clone());

    let p_depth = compute_depth(p);
    p.borrow_mut().depth = p_depth;

    let p_lc = p.borrow().left_child_count;
    let p_rc = p.borrow().right_child_count;
    l.borrow_mut().right_child_count = p_lc + p_rc + 1;

    let l_depth = compute_depth(&l);
    l.borrow_mut().depth = l_depth;

    l
}

/// Rotate left around node P. Returns the new subtree root (R).
fn bostree_rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    // Update P's parent to point to R
    let p_parent_weak = p.borrow().parent_node.clone();
    if let Some(ref pw) = p_parent_weak {
        if let Some(parent) = pw.upgrade() {
            let p_is_left = {
                let par_b = parent.borrow();
                par_b.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, p))
            };
            if p_is_left {
                parent.borrow_mut().left_child_node = Some(r.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(r.clone());
            }
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    r.borrow_mut().parent_node = p_parent_weak;

    // P.right = R.left (c1)
    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    {
        let mut pb = p.borrow_mut();
        pb.right_child_node = r_left.clone();
        pb.right_child_count = r_left_count;
    }

    if let Some(ref rl) = r_left {
        rl.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
    r.borrow_mut().left_child_node = Some(p.clone());

    let p_depth = compute_depth(p);
    p.borrow_mut().depth = p_depth;

    let p_lc = p.borrow().left_child_count;
    let p_rc = p.borrow().right_child_count;
    r.borrow_mut().left_child_count = p_lc + p_rc + 1;

    let r_depth = compute_depth(&r);
    r.borrow_mut().depth = r_depth;

    r
}

// ============================================================================
// BOSTree methods
// ============================================================================

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        self.root_node.as_ref().map_or(0, |root| {
            let rb = root.borrow();
            rb.left_child_count + rb.right_child_count + 1
        })
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut current = self.root_node.clone();
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        while current.is_some() {
            let node = current.as_ref().unwrap().clone();
            parent_node = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                current = node.borrow().left_child_node.clone();
            } else {
                node.borrow_mut().right_child_count += 1;
                current = node.borrow().right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(ref parent) = parent_node {
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent.borrow().key);
            if cmp < 0 {
                parent.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        let depth_increased = {
            let pb = parent_node.as_ref().unwrap().borrow();
            pb.left_child_node.is_some() ^ pb.right_child_node.is_some()
        };

        if depth_increased {
            let mut bubble = parent_node.clone();
            if let Some(ref b) = bubble {
                b.borrow_mut().depth += 1;
            }

            while bubble.is_some() {
                let b = bubble.as_ref().unwrap().clone();
                let parent_of_b = b.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

                if let Some(ref grandparent) = parent_of_b {
                    let new_left_depth = grandparent
                        .borrow()
                        .left_child_node
                        .as_ref()
                        .map_or(0, |c| c.borrow().depth + 1);
                    let new_right_depth = grandparent
                        .borrow()
                        .right_child_node
                        .as_ref()
                        .map_or(0, |c| c.borrow().depth + 1);
                    let max_depth = new_left_depth.max(new_right_depth);

                    if grandparent.borrow().depth != max_depth {
                        grandparent.borrow_mut().depth = max_depth;
                    } else {
                        break;
                    }

                    if new_left_depth == new_right_depth + 2 {
                        let left_child = grandparent.borrow().left_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&left_child) > 0 {
                            bostree_rotate_left(self, &left_child);
                        }
                        let gp = grandparent.clone();
                        bostree_rotate_right(self, &gp);
                    } else if new_right_depth == new_left_depth + 2 {
                        let right_child = grandparent.borrow().right_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&right_child) < 0 {
                            bostree_rotate_right(self, &right_child);
                        }
                        let gp = grandparent.clone();
                        bostree_rotate_left(self, &gp);
                    }
                }

                bubble = parent_of_b;
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let bubble_up: Option<Rc<RefCell<BOSNode>>>;

        let has_both_children = {
            let nb = node.borrow();
            nb.left_child_node.is_some() && nb.right_child_node.is_some()
        };

        if has_both_children {
            let left_depth = node.borrow().left_child_node.as_ref().unwrap().borrow().depth;
            let right_depth = node.borrow().right_child_node.as_ref().unwrap().borrow().depth;

            let (candidate, lost_child, bubble_start) = if left_depth >= right_depth {
                node.borrow_mut().left_child_count -= 1;
                let left_child = node.borrow().left_child_node.as_ref().unwrap().clone();

                let mut cand = left_child.clone();
                while cand.borrow().right_child_node.is_some() {
                    cand.borrow_mut().right_child_count -= 1;
                    let next = cand.borrow().right_child_node.as_ref().unwrap().clone();
                    cand = next;
                }
                let lost = cand.borrow().left_child_node.clone();
                let bs = cand.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();
                (cand, lost, bs)
            } else {
                node.borrow_mut().right_child_count -= 1;
                let right_child = node.borrow().right_child_node.as_ref().unwrap().clone();

                let mut cand = right_child.clone();
                while cand.borrow().left_child_node.is_some() {
                    cand.borrow_mut().left_child_count -= 1;
                    let next = cand.borrow().left_child_node.as_ref().unwrap().clone();
                    cand = next;
                }
                let lost = cand.borrow().right_child_node.clone();
                let bs = cand.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();
                (cand, lost, bs)
            };

            // Detach lost_child from candidate's old position
            let bs_is_left = {
                let bsb = bubble_start.borrow();
                bsb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &candidate))
            };
            if bs_is_left {
                bubble_start.borrow_mut().left_child_node = lost_child.clone();
            } else {
                bubble_start.borrow_mut().right_child_node = lost_child.clone();
            }
            if let Some(ref lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Move candidate to node's position
            let node_parent_weak = node.borrow().parent_node.clone();
            if let Some(ref pw) = node_parent_weak {
                if let Some(parent) = pw.upgrade() {
                    let node_is_left = {
                        let pb = parent.borrow();
                        pb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node))
                    };
                    if node_is_left {
                        parent.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        parent.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = node_parent_weak;

            // Move node's children to candidate
            let node_left = node.borrow().left_child_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right = node.borrow().right_child_node.clone();
            let node_right_count = node.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = node_left.clone();
            candidate.borrow_mut().left_child_count = node_left_count;
            candidate.borrow_mut().right_child_node = node_right.clone();
            candidate.borrow_mut().right_child_count = node_right_count;

            if let Some(ref nl) = node_left {
                nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref nr) = node_right {
                nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate (if bubble_start != node)
            let bubble_start_is_node = Rc::ptr_eq(&bubble_start, node);
            if !bubble_start_is_node {
                let mut bs = Some(bubble_start.clone());
                while bs.is_some() {
                    let b = bs.as_ref().unwrap().clone();
                    if Rc::ptr_eq(&b, &candidate) {
                        break;
                    }

                    let new_depth = compute_depth(&b);
                    b.borrow_mut().depth = new_depth;

                    let balance = bostree_balance(&b);
                    // Capture the rotation result, just like C does:
                    // bubble_start = _bostree_rotate_left(tree, bubble_start)
                    let new_root = if balance > 1 {
                        let rc = b.borrow().right_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&rc) < 0 {
                            bostree_rotate_right(self, &rc);
                        }
                        bostree_rotate_left(self, &b)
                    } else if balance < -1 {
                        let lc = b.borrow().left_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&lc) > 0 {
                            bostree_rotate_left(self, &lc);
                        }
                        bostree_rotate_right(self, &b)
                    } else {
                        b.clone()
                    };

                    bs = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                }
            }

            // Fix candidate's depth
            let cand_depth = compute_depth(&candidate);
            candidate.borrow_mut().depth = cand_depth;

            // Bubble up from candidate's parent
            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            // Fix immediate parent's child count
            if let Some(ref bu) = bubble_up {
                let cand_is_left = {
                    let bub = bu.borrow();
                    bub.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &candidate))
                };
                if cand_is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // At most one child
            let node_parent = node.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            if node_parent.is_none() {
                // Node is root
                let node_left = node.borrow().left_child_node.clone();
                let node_right = node.borrow().right_child_node.clone();

                if let Some(ref left) = node_left {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else {
                    self.root_node = node_right.clone();
                    if let Some(ref right) = node_right {
                        right.borrow_mut().parent_node = None;
                    }
                }
                bubble_up = None;
            } else {
                let parent = node_parent.unwrap();
                let (candidate, candidate_count) = {
                    let nb = node.borrow();
                    if nb.left_child_node.is_some() {
                        (nb.left_child_node.clone(), nb.left_child_count)
                    } else {
                        (nb.right_child_node.clone(), nb.right_child_count)
                    }
                };

                let node_is_left = {
                    let pb = parent.borrow();
                    pb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node))
                };

                if node_is_left {
                    parent.borrow_mut().left_child_node = candidate.clone();
                    parent.borrow_mut().left_child_count = candidate_count;
                } else {
                    parent.borrow_mut().right_child_node = candidate.clone();
                    parent.borrow_mut().right_child_count = candidate_count;
                }

                if let Some(ref cand) = candidate {
                    cand.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }

                bubble_up = Some(parent);
            }
        }

        // Main bubbling loop: update depths, rebalance, decrement child counts
        let mut bubbling_finished = false;
        let mut current = bubble_up;

        while current.is_some() {
            let bu = current.as_ref().unwrap().clone();

            if !bubbling_finished {
                let left_depth = bu
                    .borrow()
                    .left_child_node
                    .as_ref()
                    .map_or(0, |c| c.borrow().depth + 1);
                let right_depth = bu
                    .borrow()
                    .right_child_node
                    .as_ref()
                    .map_or(0, |c| c.borrow().depth + 1);
                let new_depth = left_depth.max(right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let balance = bostree_balance(&bu);
                // Capture rotation result like C: bubble_up = _bostree_rotate_right(tree, bubble_up)
                let new_root = if balance < -1 {
                    let lc = bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&lc) > 0 {
                        bostree_rotate_left(self, &lc);
                    }
                    bostree_rotate_right(self, &bu)
                } else if balance > 1 {
                    let rc = bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&rc) < 0 {
                        bostree_rotate_right(self, &rc);
                    }
                    bostree_rotate_left(self, &bu)
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                    bu.clone()
                };

                // Use the new root for child count decrement and parent traversal
                // (matches C: after rotation, bubble_up is the new root)
                let grandparent = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                if let Some(ref gp) = grandparent {
                    let new_root_is_left = {
                        let gpb = gp.borrow();
                        gpb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &new_root))
                    };
                    if new_root_is_left {
                        gp.borrow_mut().left_child_count -= 1;
                    } else {
                        gp.borrow_mut().right_child_count -= 1;
                    }
                }
                current = grandparent;
            } else {
                // Only decrement child counts, no rebalancing needed
                let grandparent = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                if let Some(ref gp) = grandparent {
                    let bu_is_left = {
                        let gpb = gp.borrow();
                        gpb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &bu))
                    };
                    if bu_is_left {
                        gp.borrow_mut().left_child_count -= 1;
                    } else {
                        gp.borrow_mut().right_child_count -= 1;
                    }
                }
                current = grandparent;
            }
        }

        // Mark node as invalid and unref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let count = node.borrow().weak_ref_count;
        let valid = node.borrow().weak_ref_node_valid;

        if count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while current.is_some() {
            let node = current.as_ref().unwrap().clone();
            let cmp = (self.cmp_function)(key, &node.borrow().key);
            if cmp == 0 {
                return Some(node);
            } else if cmp < 0 {
                current = node.borrow().left_child_node.clone();
            } else {
                current = node.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        let mut idx = index;
        while current.is_some() {
            let node = current.as_ref().unwrap().clone();
            let left_count = node.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(node);
                }
                idx -= 1;
                current = node.borrow().right_child_node.clone();
            } else {
                current = node.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }
        println!("digraph {{\n  ordering = out;");
        if let Some(ref root) = self.root_node {
            Self::print_helper(root);
        }
        println!("}}");
    }

    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let key = node.borrow().key.clone();
        let left_count = node.borrow().left_child_count;
        let right_count = node.borrow().right_child_count;
        let depth = node.borrow().depth;
        println!(
            "  {} [label=\"\\N ({},{},{})\"];",
            key, left_count, right_count, depth
        );

        let parent_key = {
            let nb = node.borrow();
            nb.parent_node.as_ref().and_then(|pw| pw.upgrade()).map(|p| p.borrow().key.clone())
        };
        if let Some(ref pk) = parent_key {
            println!("  {} -> {} [color=green];", key, pk);
        }

        let left = node.borrow().left_child_node.clone();
        if let Some(ref l) = left {
            println!("  {} -> {}", key, l.borrow().key);
            Self::print_helper(l);
        }

        let right = node.borrow().right_child_node.clone();
        if let Some(ref r) = right {
            println!("  {} -> {}", key, r.borrow().key);
            Self::print_helper(r);
        }
    }
}

// ============================================================================
// Standalone functions
// ============================================================================

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let count = node.borrow().weak_ref_count;
    assert!(count < 127, "weak_ref_count overflow");
    assert!(count > 0, "weak_ref_count is zero");
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right = node.borrow().right_child_node.clone();
    if let Some(ref right_node) = right {
        let mut current = right_node.clone();
        loop {
            let left = current.borrow().left_child_node.clone();
            if left.is_none() {
                break;
            }
            current = left.unwrap();
        }
        return Some(current);
    }

    let mut current = node.clone();
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        if let Some(ref pw) = parent_weak {
            if let Some(parent) = pw.upgrade() {
                let is_right = {
                    let pb = parent.borrow();
                    pb.right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &current))
                };
                if is_right {
                    current = parent;
                    continue;
                } else {
                    return Some(parent);
                }
            }
        }
        return None;
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left = node.borrow().left_child_node.clone();
    if let Some(ref left_node) = left {
        let mut current = left_node.clone();
        loop {
            let right = current.borrow().right_child_node.clone();
            if right.is_none() {
