                        pb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node))
                    };
                    if node_is_left {
                        parent.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        parent.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = node_parent_weak;

            // Move node's children to candidate
            let node_left = node.borrow().left_child_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right = node.borrow().right_child_node.clone();
            let node_right_count = node.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = node_left.clone();
            candidate.borrow_mut().left_child_count = node_left_count;
            candidate.borrow_mut().right_child_node = node_right.clone();
            candidate.borrow_mut().right_child_count = node_right_count;

            if let Some(ref nl) = node_left {
                nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref nr) = node_right {
                nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate (if bubble_start != node)
            let bubble_start_is_node = Rc::ptr_eq(&bubble_start, node);
            if !bubble_start_is_node {
                let mut bs = Some(bubble_start.clone());
                while let Some(b) = bs {
                    if Rc::ptr_eq(&b, &candidate) {
                        break;
                    }

                    let new_depth = compute_depth(&b);
                    b.borrow_mut().depth = new_depth;

                    let balance = bostree_balance(&b);
                    let new_root = if balance > 1 {
                        let rc = b.borrow().right_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&rc) < 0 {
                            bostree_rotate_right(self, &rc);
                        }
                        bostree_rotate_left(self, &b)
                    } else if balance < -1 {
                        let lc = b.borrow().left_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&lc) > 0 {
                            bostree_rotate_left(self, &lc);
                        }
                        bostree_rotate_right(self, &b)
                    } else {
                        b.clone()
                    };

                    bs = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                }
            }

            // Fix candidate's depth
            let cand_depth = compute_depth(&candidate);
            candidate.borrow_mut().depth = cand_depth;

            // Bubble up from candidate's parent
            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            // Fix immediate parent's child count
            if let Some(ref bu) = bubble_up {
                let cand_is_left = {
                    let bub = bu.borrow();
                    bub.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &candidate))
                };
                if cand_is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // At most one child
            let node_parent = node.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            if node_parent.is_none() {
                // Node is root
                let node_left = node.borrow().left_child_node.clone();
                let node_right = node.borrow().right_child_node.clone();

                if let Some(ref left) = node_left {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else {
                    self.root_node = node_right.clone();
                    if let Some(ref right) = node_right {
                        right.borrow_mut().parent_node = None;
                    }
                }
                bubble_up = None;
            } else {
                let parent = node_parent.unwrap();
                let (candidate, candidate_count) = {
                    let nb = node.borrow();
                    if nb.left_child_node.is_some() {
                        (nb.left_child_node.clone(), nb.left_child_count)
                    } else {
                        (nb.right_child_node.clone(), nb.right_child_count)
                    }
                };

                let node_is_left = {
                    let pb = parent.borrow();
                    pb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node))
                };

                if node_is_left {
                    parent.borrow_mut().left_child_node = candidate.clone();
                    parent.borrow_mut().left_child_count = candidate_count;
                } else {
                    parent.borrow_mut().right_child_node = candidate.clone();
                    parent.borrow_mut().right_child_count = candidate_count;
                }

                if let Some(ref cand) = candidate {
                    cand.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }

                bubble_up = Some(parent);
            }
        }

        // Main bubbling loop
        let mut bubbling_finished = false;
        let mut current = bubble_up;

        while let Some(bu) = current {
            if !bubbling_finished {
                let left_depth = bu.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let right_depth = bu.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let new_depth = left_depth.max(right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let balance = bostree_balance(&bu);
                let new_root = if balance < -1 {
                    let lc = bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&lc) > 0 {
                        bostree_rotate_left(self, &lc);
                    }
                    bostree_rotate_right(self, &bu)
                } else if balance > 1 {
                    let rc = bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&rc) < 0 {
                        bostree_rotate_right(self, &rc);
                    }
                    bostree_rotate_left(self, &bu)
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                    bu.clone()
                };

                // Use new_root for child count decrement and parent traversal
                let grandparent = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                if let Some(ref gp) = grandparent {
                    let new_root_is_left = {
                        let gpb = gp.borrow();
                        gpb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &new_root))
                    };
                    if new_root_is_left {
                        gp.borrow_mut().left_child_count -= 1;
                    } else {
                        gp.borrow_mut().right_child_count -= 1;
                    }
                }
                current = grandparent;
            } else {
                let grandparent = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                if let Some(ref gp) = grandparent {
                    let bu_is_left = {
                        let gpb = gp.borrow();
                        gpb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &bu))
                    };
                    if bu_is_left {
                        gp.borrow_mut().left_child_count -= 1;
                    } else {
                        gp.borrow_mut().right_child_count -= 1;
                    }
                }
                current = grandparent;
            }
        }

        // Mark node as invalid and unref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let count = node.borrow().weak_ref_count;
        let valid = node.borrow().weak_ref_node_valid;

        if count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(node) = current {
            let nb = node.borrow();
            let cmp = (self.cmp_function)(key, &nb.key);
            if cmp == 0 {
                return Some(node);
            } else if cmp < 0 {
                current = nb.left_child_node.clone();
            } else {
                current = nb.right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        let mut idx = index;
        while let Some(node) = current {
            let nb = node.borrow();
            let left_count = nb.left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(node);
                }
                idx -= 1;
                current = nb.right_child_node.clone();
            } else {
                current = nb.left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }
        println!("digraph {{\n  ordering = out;");
        if let Some(ref root) = self.root_node {
            Self::print_helper(root);
        }
        println!("}}");
    }

    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let key = node.borrow().key.clone();
        let left_count = node.borrow().left_child_count;
        let right_count = node.borrow().right_child_count;
        let depth = node.borrow().depth;
        println!(
            "  {} [label=\"\\N ({},{},{})\"];",
            key, left_count, right_count, depth
        );

        let parent_key = {
            let nb = node.borrow();
            nb.parent_node.as_ref().and_then(|pw| pw.upgrade()).map(|p| p.borrow().key.clone())
        };
        if let Some(ref pk) = parent_key {
            println!("  {} -> {} [color=green];", key, pk);
        }

        let left = node.borrow().left_child_node.clone();
        if let Some(ref l) = left {
            println!("  {} -> {}", key, l.borrow().key);
            Self::print_helper(l);
        }

        let right = node.borrow().right_child_node.clone();
        if let Some(ref r) = right {
            println!("  {} -> {}", key, r.borrow().key);
            Self::print_helper(r);
        }
    }
}

// ============================================================================
// Standalone functions
// ============================================================================

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let count = node.borrow().weak_ref_count;
    assert!(count < 127, "weak_ref_count overflow");
    assert!(count > 0, "weak_ref_count is zero");
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // Check for right child
    if let Some(ref right_node) = node.borrow().right_child_node {
        // Go to right child, then keep going left
        let mut current = right_node.clone();
        while let Some(left) = current.borrow().left_child_node.clone() {
            current = left;
        }
        return Some(current);
    }

    // No right child: go up until we find a node that is a left child
    let mut current = node.clone();
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak {
            Some(ref pw) => {
                if let Some(parent) = pw.upgrade() {
                    let is_right = {
                        let pb = parent.borrow();
                        pb.right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &current))
                    };
                    if is_right {
                        current = parent;
                        continue;
                    } else {
                        return Some(parent);
                    }
                }
            }
            None => {}
        }
        return None;
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // Check for left child
    if let Some(ref left_node) = node.borrow().left_child_node {
        // Go to left child, then keep going right
        let mut current = left_node.clone();
        while let Some(right) = current.borrow().right_child_node.clone() {
            current = right;
        }
        return Some(current);
    }

    // No left child: go up until we find a node that is a right child
    let mut current = node.clone();
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak {
            Some(ref pw) => {
                if let Some(parent) = pw.upgrade() {
                    let is_left = {
                        let pb = parent.borrow();
                        pb.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &current))
                    };
                    if is_left {
                        current = parent;
                        continue;
                    } else {
                        return Some(parent);
                    }
                }
            }
            None => {}
        }
        return None;
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak {
            Some(ref pw) => {
                if let Some(parent) = pw.upgrade() {
                    let is_right = {
                        let pb = parent.borrow();
                        pb.right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &current))
                    };
                    if is_right {
                        counter += 1 + parent.borrow().left_child_count;
                    }
                    current = parent;
                    continue;
                }
            }
            None => {}
        }
        break;
    }
    counter
}
